/**
 * CSV Parser Library - TypeScript Implementation
 * Comprehensive CSV parsing with type coercion, error handling, and data aggregation
 */

/**
 * Options for CSV parsing
 */
interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

/**
 * Represents an error that occurred during parsing
 */
interface ParseError {
  row: number;
  message: string;
}

/**
 * Result type for aggregation operations
 */
type AggregateResult = number | null;

/**
 * Main result type containing parsed CSV data and metadata
 */
interface CSVResult {
  rows: Record<string, any>[];
  headers: string[];
  errors: ParseError[];
  filter(predicate: (row: Record<string, any>) => boolean): CSVResult;
  sum(column: string): AggregateResult;
  average(column: string): AggregateResult;
  count(): number;
  groupBy(column: string): Map<string, Record<string, any>[]>;
}

/**
 * Coerce a string value to its appropriate type
 * @param value - The string value to coerce
 * @returns The coerced value (string, number, boolean, or null)
 */
function coerceType(value: string): any {
  // Handle null values
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Handle booleans
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Handle numbers
  const trimmedValue = value.trim();
  if (trimmedValue !== '') {
    // Check if it's a valid number
    const numberValue = Number(trimmedValue);
    if (!isNaN(numberValue) && trimmedValue !== '') {
      return numberValue;
    }
  }

  // Return as string if no coercion matched
  return value;
}

/**
 * Parse a CSV string into an array of objects with headers as keys
 * Handles quoted fields, escaped quotes, custom delimiters, and type coercion
 * @param input - The CSV string to parse
 * @param options - Optional parsing options (delimiter, quoteChar, lineSeparator)
 * @returns CSVResult containing parsed rows, headers, errors, and utility methods
 */
function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ',';
  const quoteChar = options?.quoteChar ?? '"';
  const lineSeparator = options?.lineSeparator ?? '\n';

  const errors: ParseError[] = [];
  const rows: Record<string, any>[] = [];
  let headers: string[] = [];

  // Handle empty input
  if (!input || input.trim().length === 0) {
    return createResult([], [], [], delimiter, quoteChar, lineSeparator);
  }

  // Split by line separator to get lines
  const lines = input.split(lineSeparator);

  // Helper function to parse a single CSV line
  function parseCSVLine(line: string): string[] {
    const fields: string[] = [];
    let current = '';
    let inQuotes = false;
    let i = 0;

    while (i < line.length) {
      const char = line[i];
      const nextChar = i + 1 < line.length ? line[i + 1] : '';

      if (char === quoteChar) {
        if (inQuotes && nextChar === quoteChar) {
          // Escaped quote: two quotes in a row = one literal quote
          current += quoteChar;
          i += 2;
        } else {
          // Toggle quote mode
          inQuotes = !inQuotes;
          i++;
        }
      } else if (char === delimiter && !inQuotes) {
        // End of field
        fields.push(current);
        current = '';
        i++;
      } else {
        // Regular character
        current += char;
        i++;
      }
    }

    // Add the last field
    fields.push(current);

    return fields;
  }

  // Process each line
  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    // Skip empty lines
    if (line.trim().length === 0) {
      continue;
    }

    const fields = parseCSVLine(line);

    // First line is headers
    if (headers.length === 0) {
      headers = fields.map((field) => field.trim());
      continue;
    }

    // Validate row has correct number of fields
    if (fields.length !== headers.length) {
      errors.push({
        row: lineIndex,
        message: `Row has ${fields.length} fields but expected ${headers.length}`,
      });
      continue;
    }

    // Create row object with type coercion
    const row: Record<string, any> = {};
    for (let i = 0; i < headers.length; i++) {
      const fieldValue = fields[i].trim();
      row[headers[i]] = coerceType(fieldValue);
    }

    rows.push(row);
  }

  return createResult(rows, headers, errors, delimiter, quoteChar, lineSeparator);
}

/**
 * Create a CSVResult object with all utility methods
 */
function createResult(
  rows: Record<string, any>[],
  headers: string[],
  errors: ParseError[],
  delimiter: string,
  quoteChar: string,
  lineSeparator: string
): CSVResult {
  return {
    rows,
    headers,
    errors,

    /**
     * Filter rows based on a predicate function
     */
    filter(predicate: (row: Record<string, any>) => boolean): CSVResult {
      const filteredRows = rows.filter(predicate);
      return createResult(
        filteredRows,
        headers,
        errors,
        delimiter,
        quoteChar,
        lineSeparator
      );
    },

    /**
     * Sum numeric values in a column
     */
    sum(column: string): AggregateResult {
      if (!headers.includes(column)) {
        return null;
      }

      let sum = 0;
      let count = 0;

      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number' && !isNaN(value)) {
          sum += value;
          count++;
        }
      }

      return count > 0 ? sum : null;
    },

    /**
     * Calculate average of numeric values in a column
     */
    average(column: string): AggregateResult {
      if (!headers.includes(column)) {
        return null;
      }

      let sum = 0;
      let count = 0;

      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number' && !isNaN(value)) {
          sum += value;
          count++;
        }
      }

      return count > 0 ? sum / count : null;
    },

    /**
     * Count total rows
     */
    count(): number {
      return rows.length;
    },

    /**
     * Group rows by a column's values
     */
    groupBy(column: string): Map<string, Record<string, any>[]> {
      const groups = new Map<string, Record<string, any>[]>();

      if (!headers.includes(column)) {
        return groups;
      }

      for (const row of rows) {
        const key = String(row[column] ?? 'null');

        if (!groups.has(key)) {
          groups.set(key, []);
        }

        groups.get(key)!.push(row);
      }

      return groups;
    },
  };
}

export { parseCSV, CSVOptions, CSVResult, ParseError, coerceType };

/**
 * Comprehensive Test Suite for CSV Parser Library
 */

import { parseCSV, coerceType } from './csv-parser';

/**
 * Test assertion helper
 */
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

/**
 * Deep equality check for objects and arrays
 */
function deepEqual(a: any, b: any, path = ''): boolean {
  if (a === b) return true;
  if (a === null || b === null) return a === b;
  if (typeof a !== typeof b) return false;

  if (typeof a === 'object') {
    if (Array.isArray(a) !== Array.isArray(b)) return false;

    const keysA = Object.keys(a);
    const keysB = Object.keys(b);

    if (keysA.length !== keysB.length) return false;

    for (const key of keysA) {
      if (!keysB.includes(key)) return false;
      if (!deepEqual(a[key], b[key], `${path}.${key}`)) return false;
    }

    return true;
  }

  return false;
}

/**
 * Test 1: Basic CSV Parsing
 */
function testBasicParsing(): void {
  const csv = `name,age,city
John,30,New York
Jane,25,San Francisco`;

  const result = parseCSV(csv);

  assert(result.headers.length === 3, 'Should have 3 headers');
  assert(
    deepEqual(result.headers, ['name', 'age', 'city']),
    'Headers should match'
  );
  assert(result.rows.length === 2, 'Should have 2 rows');
  assert(result.errors.length === 0, 'Should have no errors');
  assert(result.rows[0].name === 'John', 'First row name should be John');
  assert(result.rows[0].age === 30, 'First row age should be 30 (coerced to number)');
  assert(result.rows[1].city === 'San Francisco', 'City should be preserved');

  console.log('✓ Test 1: Basic CSV Parsing - PASSED');
}

/**
 * Test 2: Quoted Fields with Commas
 */
function testQuotedFields(): void {
  const csv = `name,address,comment
"Smith, John",123 Main St,"Lives in the city"
"Doe, Jane","456 Oak Ave, Apt 2","Has a dog"`;

  const result = parseCSV(csv);

  assert(result.rows.length === 2, 'Should have 2 rows');
  assert(
    result.rows[0].name === 'Smith, John',
    'Quoted field with comma should preserve comma'
  );
  assert(
    result.rows[0].address === '123 Main St',
    'Address should be parsed correctly'
  );
  assert(
    result.rows[1].address === '456 Oak Ave, Apt 2',
    'Address with comma should be preserved'
  );
  assert(
    result.rows[0].comment === 'Lives in the city',
    'Comment should be parsed correctly'
  );
  assert(result.errors.length === 0, 'Should have no errors');

  console.log('✓ Test 2: Quoted Fields with Commas - PASSED');
}

/**
 * Test 3: Escaped Quotes (Double Quotes)
 */
function testEscapedQuotes(): void {
  const csv = `product,description
"Laptop","High-performance machine with ""Intel"" processor"
"Phone","Smartphone with ""5G"" connectivity"`;

  const result = parseCSV(csv);

  assert(result.rows.length === 2, 'Should have 2 rows');
  assert(
    result.rows[0].description.includes('Intel'),
    'Escaped quotes should be unescaped'
  );
  assert(
    result.rows[0].description === 'High-performance machine with "Intel" processor',
    'Escaped quotes should become single quotes'
  );
  assert(
    result.rows[1].description === 'Smartphone with "5G" connectivity',
    'Multiple escaped quotes should work'
  );
  assert(result.errors.length === 0, 'Should have no errors');

  console.log('✓ Test 3: Escaped Quotes - PASSED');
}

/**
 * Test 4: Custom Delimiters
 */
function testCustomDelimiters(): void {
  const csv = `name|age|city
John|30|New York
Jane|25|Los Angeles`;

  const result = parseCSV(csv, { delimiter: '|' });

  assert(result.headers.length === 3, 'Should parse with pipe delimiter');
  assert(result.rows.length === 2, 'Should have 2 rows');
  assert(result.rows[0].name === 'John', 'Data should be correct with pipe delimiter');
  assert(result.rows[1].city === 'Los Angeles', 'City should be correct');

  console.log('✓ Test 4: Custom Delimiters - PASSED');
}

/**
 * Test 5: Custom Quote Character
 */
function testCustomQuoteChar(): void {
  const csv = `name,address
'Smith, John','123 Main St, Apt 1'
'Doe, Jane','456 Oak Ave'`;

  const result = parseCSV(csv, { quoteChar: "'" });

  assert(result.rows.length === 2, 'Should parse with single quote');
  assert(
    result.rows[0].name === 'Smith, John',
    'Single-quoted fields should preserve commas'
  );
  assert(result.errors.length === 0, 'Should have no errors');

  console.log('✓ Test 5: Custom Quote Character - PASSED');
}

/**
 * Test 6: Custom Line Separator
 */
function testCustomLineSeparator(): void {
  const csv = `name,age;John,30;Jane,25`;

  const result = parseCSV(csv, { lineSeparator: ';' });

  assert(result.rows.length === 2, 'Should parse with semicolon line separator');
  assert(result.rows[0].name === 'John', 'First row should be correct');
  assert(result.rows[1].name === 'Jane', 'Second row should be correct');

  console.log('✓ Test 6: Custom Line Separator - PASSED');
}

/**
 * Test 7: Type Coercion - Numbers
 */
function testTypeCoercionNumbers(): void {
  const csv = `id,price,quantity
1,19.99,5
2,100,10
3,-50.5,0`;

  const result = parseCSV(csv);

  assert(result.rows[0].id === 1, 'Integer should be coerced to number');
  assert(typeof result.rows[0].id === 'number', 'ID should be a number');
  assert(result.rows[0].price === 19.99, 'Float should be coerced to number');
  assert(typeof result.rows[0].price === 'number', 'Price should be a number');
  assert(result.rows[2].price === -50.5, 'Negative float should be coerced');
  assert(result.rows[2].quantity === 0, 'Zero should be coerced to number');

  console.log('✓ Test 7: Type Coercion - Numbers - PASSED');
}

/**
 * Test 8: Type Coercion - Booleans
 */
function testTypeCoercionBooleans(): void {
  const csv = `id,active,disabled
1,true,false
2,True,False
3,TRUE,FALSE`;

  const result = parseCSV(csv);

  assert(result.rows[0].active === true, 'true should be coerced to boolean');
  assert(typeof result.rows[0].active === 'boolean', 'active should be boolean');
  assert(result.rows[0].disabled === false, 'false should be coerced to boolean');
  assert(typeof result.rows[0].disabled === 'boolean', 'disabled should be boolean');
  assert(result.rows[1].active === true, 'True (capital) should be coerced');
  assert(result.rows[2].disabled === false, 'FALSE (all caps) should be coerced');

  console.log('✓ Test 8: Type Coercion - Booleans - PASSED');
}

/**
 * Test 9: Type Coercion - Null Values
 */
function testTypeCoercionNull(): void {
  const csv = `id,name,description
1,John,
2,Jane,null
3,Bob,NULL`;

  const result = parseCSV(csv);

  assert(result.rows[0].description === null, 'Empty string should be null');
  assert(result.rows[1].description === null, 'Lowercase null should be coerced');
  assert(result.rows[2].description === null, 'Uppercase NULL should be coerced');

  console.log('✓ Test 9: Type Coercion - Null Values - PASSED');
}

/**
 * Test 10: Type Coercion - Strings
 */
function testTypeCoercionStrings(): void {
  const csv = `id,email,status
1,john@example.com,pending
2,jane@example.com,active
3,bob@example.com,inactive`;

  const result = parseCSV(csv);

  assert(typeof result.rows[0].email === 'string', 'Email should be string');
  assert(result.rows[0].email === 'john@example.com', 'Email should be preserved');
  assert(typeof result.rows[0].status === 'string', 'Status should be string');
  assert(result.rows[1].status === 'active', 'Status should be preserved');

  console.log('✓ Test 10: Type Coercion - Strings - PASSED');
}

/**
 * Test 11: Malformed Row - Different Field Count
 */
function testMalformedRowDifferentFieldCount(): void {
  const csv = `name,age,city
John,30,New York
Jane,25
Bob,35,Los Angeles,Extra`;

  const result = parseCSV(csv);

  assert(result.errors.length === 2, 'Should have 2 errors for malformed rows');
  assert(
    result.errors[0].row === 2,
    'First error should be on row 2 (0-indexed)'
  );
  assert(
    result.errors[0].message.includes('fields'),
    'Error message should mention fields'
  );
  assert(result.rows.length === 1, 'Should only have 1 valid row');
  assert(result.rows[0].name === 'John', 'First row should be valid');

  console.log('✓ Test 11: Malformed Row - Different Field Count - PASSED');
}

/**
 * Test 12: Malformed Row Error Collection
 */
function testMalformedRowErrorCollection(): void {
  const csv = `id,name,value
1,Alice,100
2,Bob
3,Charlie,300
4,David`;

  const result = parseCSV(csv);

  assert(result.errors.length === 2, 'Should collect multiple errors');
  assert(result.rows.length === 2, 'Should parse 2 valid rows');
  assert(result.rows[0].id === 1, 'First valid row should be Alice');
  assert(result.rows[1].id === 3, 'Second valid row should be Charlie');

  console.log('✓ Test 12: Malformed Row Error Collection - PASSED');
}

/**
 * Test 13: Filter Functionality
 */
function testFilter(): void {
  const csv = `name,age,city
John,30,New York
Jane,25,San Francisco
Bob,35,Los Angeles
Alice,28,Chicago`;

  const result = parseCSV(csv);
  const filtered = result.filter((row) => row.age > 28);

  assert(filtered.rows.length === 3, 'Should have 3 rows with age > 28');
  assert(filtered.rows[0].name === 'John', 'John should be in filtered results');
  assert(filtered.rows[1].name === 'Bob', 'Bob should be in filtered results');
  assert(filtered.rows[2].name === 'Alice', 'Alice should be in filtered results');

  // Filter for specific string
  const sfOnly = result.filter((row) => row.city === 'San Francisco');
  assert(sfOnly.rows.length === 1, 'Should have 1 row for San Francisco');
  assert(sfOnly.rows[0].name === 'Jane', 'Jane should be the only SF resident');

  console.log('✓ Test 13: Filter Functionality - PASSED');
}

/**
 * Test 14: Sum Aggregation
 */
function testSum(): void {
  const csv = `product,price,quantity
Apple,1.50,10
Banana,0.75,20
Orange,2.00,5
Grape,3.50,15`;

  const result = parseCSV(csv);

  const priceSum = result.sum('price');
  assert(priceSum === 7.75, `Price sum should be 7.75, got ${priceSum}`);

  const quantitySum = result.sum('quantity');
  assert(quantitySum === 50, `Quantity sum should be 50, got ${quantitySum}`);

  // Test sum on non-numeric column
  const productSum = result.sum('product');
  assert(productSum === null, 'Sum of non-numeric column should be null');

  // Test sum on non-existent column
  const nonExistent = result.sum('nonexistent');
  assert(nonExistent === null, 'Sum of non-existent column should be null');

  console.log('✓ Test 14: Sum Aggregation - PASSED');
}

/**
 * Test 15: Average Aggregation
 */
function testAverage(): void {
  const csv = `student,score
Alice,95
Bob,85
Charlie,90
Diana,100`;

  const result = parseCSV(csv);

  const avg = result.average('score');
  const expectedAvg = (95 + 85 + 90 + 100) / 4;
  assert(avg === expectedAvg, `Average should be ${expectedAvg}, got ${avg}`);

  // Test average on non-numeric column
  const studentAvg = result.average('student');
  assert(studentAvg === null, 'Average of non-numeric column should be null');

  // Test average on non-existent column
  const nonExistent = result.average('nonexistent');
  assert(nonExistent === null, 'Average of non-existent column should be null');

  console.log('✓ Test 15: Average Aggregation - PASSED');
}

/**
 * Test 16: Count
 */
function testCount(): void {
  const csv = `id,name
1,Alice
2,Bob
3,Charlie
4,Diana
5,Eve`;

  const result = parseCSV(csv);

  assert(result.count() === 5, 'Count should return 5');

  // Count after filtering
  const filtered = result.filter((row) => row.id <= 3);
  assert(filtered.count() === 3, 'Filtered count should be 3');

  console.log('✓ Test 16: Count - PASSED');
}

/**
 * Test 17: GroupBy
 */
function testGroupBy(): void {
  const csv = `department,name,salary
Sales,Alice,50000
Engineering,Bob,80000
Sales,Charlie,55000
Engineering,Diana,85000
Sales,Eve,52000`;

  const result = parseCSV(csv);
  const grouped = result.groupBy('department');

  assert(grouped.has('Sales'), 'Should have Sales group');
  assert(grouped.has('Engineering'), 'Should have Engineering group');

  const sales = grouped.get('Sales')!;
  assert(sales.length === 3, 'Sales group should have 3 members');
  assert(sales[0].name === 'Alice', 'First sales member is Alice');
  assert(sales[1].name === 'Charlie', 'Second sales member is Charlie');
  assert(sales[2].name === 'Eve', 'Third sales member is Eve');

  const engineering = grouped.get('Engineering')!;
  assert(engineering.length === 2, 'Engineering group should have 2 members');

  console.log('✓ Test 17: GroupBy - PASSED');
}

/**
 * Test 18: GroupBy with Null Values
 */
function testGroupByWithNullValues(): void {
  const csv = `status,count
active,10
inactive,5
,3
active,8`;

  const result = parseCSV(csv);
  const grouped = result.groupBy('status');

  assert(grouped.has('active'), 'Should have active group');
  assert(grouped.has('inactive'), 'Should have inactive group');
  assert(grouped.has('null'), 'Should have null group as "null" string');

  const nullGroup = grouped.get('null')!;
  assert(nullGroup.length === 1, 'Null group should have 1 member');

  console.log('✓ Test 18: GroupBy with Null Values - PASSED');
}

/**
 * Test 19: Empty Input
 */
function testEmptyInput(): void {
  const result = parseCSV('');

  assert(result.rows.length === 0, 'Empty input should have no rows');
  assert(result.headers.length === 0, 'Empty input should have no headers');
  assert(result.errors.length === 0, 'Empty input should have no errors');

  console.log('✓ Test 19: Empty Input - PASSED');
}

/**
 * Test 20: Single Column
 */
function testSingleColumn(): void {
  const csv = `name
Alice
Bob
Charlie`;

  const result = parseCSV(csv);

  assert(result.headers.length === 1, 'Should have 1 header');
  assert(result.headers[0] === 'name', 'Header should be name');
  assert(result.rows.length === 3, 'Should have 3 rows');
  assert(result.rows[0].name === 'Alice', 'First row should have name');

  console.log('✓ Test 20: Single Column - PASSED');
}

/**
 * Test 21: Single Row
 */
function testSingleRow(): void {
  const csv = `id,name,email
1,Alice,alice@example.com`;

  const result = parseCSV(csv);

  assert(result.rows.length === 1, 'Should have 1 row');
  assert(result.headers.length === 3, 'Should have 3 headers');
  assert(result.rows[0].id === 1, 'ID should be coerced to number');
  assert(result.rows[0].name === 'Alice', 'Name should be preserved');

  console.log('✓ Test 21: Single Row - PASSED');
}

/**
 * Test 22: Large Field Values
 */
function testLargeFieldValues(): void {
  const longText = 'A'.repeat(10000);
  const csv = `id,text
1,"${longText}"
2,"Short text"`;

  const result = parseCSV(csv);

  assert(result.rows.length === 2, 'Should parse 2 rows');
  assert(
    result.rows[0].text.length === 10000,
    'Should preserve long field values'
  );
  assert(result.rows[1].text === 'Short text', 'Should parse short text correctly');

  console.log('✓ Test 22: Large Field Values - PASSED');
}

/**
 * Test 23: Special Characters in Fields
 */
function testSpecialCharactersInFields(): void {
  const csv = `name,notes
"Alice","Has @special #chars"
"Bob","Contains $$ and %% symbols"
"Charlie","Email: test@example.com"`;

  const result = parseCSV(csv);

  assert(result.rows.length === 3, 'Should parse 3 rows');
  assert(
    result.rows[0].notes === 'Has @special #chars',
    'Should preserve special characters'
  );
  assert(
    result.rows[1].notes === 'Contains $$ and %% symbols',
    'Should preserve dollar and percent signs'
  );
  assert(
    result.rows[2].notes === 'Email: test@example.com',
    'Should preserve email addresses'
  );

  console.log('✓ Test 23: Special Characters in Fields - PASSED');
}

/**
 * Test 24: Mixed Quoted and Unquoted Fields
 */
function testMixedQuotedUnquoted(): void {
  const csv = `name,value,description
Alice,100,"Important note"
Bob,200,Regular
"Charlie",300,"Another note"`;

  const result = parseCSV(csv);

  assert(result.rows.length === 3, 'Should parse 3 rows');
  assert(result.rows[0].name === 'Alice', 'Unquoted name should work');
  assert(
    result.rows[0].description === 'Important note',
    'Quoted description should work'
  );
  assert(result.rows[1].description === 'Regular', 'Unquoted field should work');
  assert(result.rows[2].name === 'Charlie', 'Quoted name should work');

  console.log('✓ Test 24: Mixed Quoted and Unquoted Fields - PASSED');
}

/**
 * Test 25: Filter with Aggregation Chaining
 */
function testFilterWithAggregation(): void {
  const csv = `department,salary
Sales,50000
Engineering,80000
Sales,55000
Engineering,85000
Sales,52000`;

  const result = parseCSV(csv);

  // Filter for Sales and get average
  const salesOnly = result.filter((row) => row.department === 'Sales');
  const salesAvg = salesOnly.average('salary');
  const expectedAvg = (50000 + 55000 + 52000) / 3;

  assert(
    salesAvg === expectedAvg,
    `Sales average should be ${expectedAvg}, got ${salesAvg}`
  );
  assert(salesOnly.count() === 3, 'Sales filtered count should be 3');

  console.log('✓ Test 25: Filter with Aggregation Chaining - PASSED');
}

/**
 * Test 26: Empty Quoted Fields
 */
function testEmptyQuotedFields(): void {
  const csv = `name,value,description
"","",""`"Bob",100,"test"`;

  const result = parseCSV(csv);

