/**
 * CSV Parser Library - JavaScript Implementation
 * Comprehensive CSV parsing with type coercion, error handling, and data aggregation
 */

/**
 * Coerce a string value to its appropriate type
 * @param {string} value - The string value to coerce
 * @returns {any} The coerced value (string, number, boolean, or null)
 */
function coerceType(value) {
  // Handle null values
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Handle booleans
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Handle numbers
  const trimmedValue = value.trim();
  if (trimmedValue !== '') {
    // Check if it's a valid number
    const numberValue = Number(trimmedValue);
    if (!isNaN(numberValue) && trimmedValue !== '') {
      return numberValue;
    }
  }

  // Return as string if no coercion matched
  return value;
}

/**
 * Parse a CSV string into an array of objects with headers as keys
 * Handles quoted fields, escaped quotes, custom delimiters, and type coercion
 * @param {string} input - The CSV string to parse
 * @param {Object} options - Optional parsing options
 * @returns {Object} CSVResult containing parsed rows, headers, errors, and utility methods
 */
function parseCSV(input, options = {}) {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  const errors = [];
  const rows = [];
  let headers = [];

  // Handle empty input
  if (!input || input.trim().length === 0) {
    return createResult([], [], [], delimiter, quoteChar, lineSeparator);
  }

  // Split by line separator to get lines
  const lines = input.split(lineSeparator);

  // Helper function to parse a single CSV line
  function parseCSVLine(line) {
    const fields = [];
    let current = '';
    let inQuotes = false;
    let i = 0;

    while (i < line.length) {
      const char = line[i];
      const nextChar = i + 1 < line.length ? line[i + 1] : '';

      if (char === quoteChar) {
        if (inQuotes && nextChar === quoteChar) {
          // Escaped quote: two quotes in a row = one literal quote
          current += quoteChar;
          i += 2;
        } else {
          // Toggle quote mode
          inQuotes = !inQuotes;
          i++;
        }
      } else if (char === delimiter && !inQuotes) {
        // End of field
        fields.push(current);
        current = '';
        i++;
      } else {
        // Regular character
        current += char;
        i++;
      }
    }

    // Add the last field
    fields.push(current);

    return fields;
  }

  // Process each line
  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    // Skip empty lines
    if (line.trim().length === 0) {
      continue;
    }

    const fields = parseCSVLine(line);

    // First line is headers
    if (headers.length === 0) {
      headers = fields.map((field) => field.trim());
      continue;
    }

    // Validate row has correct number of fields
    if (fields.length !== headers.length) {
      errors.push({
        row: lineIndex,
        message: `Row has ${fields.length} fields but expected ${headers.length}`,
      });
      continue;
    }

    // Create row object with type coercion
    const row = {};
    for (let i = 0; i < headers.length; i++) {
      const fieldValue = fields[i].trim();
      row[headers[i]] = coerceType(fieldValue);
    }

    rows.push(row);
  }

  return createResult(rows, headers, errors, delimiter, quoteChar, lineSeparator);
}

/**
 * Create a CSVResult object with all utility methods
 */
function createResult(rows, headers, errors, delimiter, quoteChar, lineSeparator) {
  return {
    rows,
    headers,
    errors,

    /**
     * Filter rows based on a predicate function
     */
    filter(predicate) {
      const filteredRows = rows.filter(predicate);
      return createResult(
        filteredRows,
        headers,
        errors,
        delimiter,
        quoteChar,
        lineSeparator
      );
    },

    /**
     * Sum numeric values in a column
     */
    sum(column) {
      if (!headers.includes(column)) {
        return null;
      }

      let sum = 0;
      let count = 0;

      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number' && !isNaN(value)) {
          sum += value;
          count++;
        }
      }

      return count > 0 ? sum : null;
    },

    /**
     * Calculate average of numeric values in a column
     */
    average(column) {
      if (!headers.includes(column)) {
        return null;
      }

      let sum = 0;
      let count = 0;

      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number' && !isNaN(value)) {
          sum += value;
          count++;
        }
      }

      return count > 0 ? sum / count : null;
    },

    /**
     * Count total rows
     */
    count() {
      return rows.length;
    },

    /**
     * Group rows by a column's values
     */
    groupBy(column) {
      const groups = new Map();

      if (!headers.includes(column)) {
        return groups;
      }

      for (const row of rows) {
        const key = String(row[column] ?? 'null');

        if (!groups.has(key)) {
          groups.set(key, []);
        }

        groups.get(key).push(row);
      }

      return groups;
    },
  };
}

module.exports = { parseCSV, coerceType };

