/**
 * Comprehensive Test Suite for CSV Parser Library
 */

import { parseCSV, coerceType } from './csv-parser';

/**
 * Test assertion helper
 */
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

/**
 * Deep equality check for objects and arrays
 */
function deepEqual(a: any, b: any, path = ''): boolean {
  if (a === b) return true;
  if (a === null || b === null) return a === b;
  if (typeof a !== typeof b) return false;

  if (typeof a === 'object') {
    if (Array.isArray(a) !== Array.isArray(b)) return false;

    const keysA = Object.keys(a);
    const keysB = Object.keys(b);

    if (keysA.length !== keysB.length) return false;

    for (const key of keysA) {
      if (!keysB.includes(key)) return false;
      if (!deepEqual(a[key], b[key], `${path}.${key}`)) return false;
    }

    return true;
  }

  return false;
}

/**
 * Test 1: Basic CSV Parsing
 */
function testBasicParsing(): void {
  const csv = `name,age,city
John,30,New York
Jane,25,San Francisco`;

  const result = parseCSV(csv);

  assert(result.headers.length === 3, 'Should have 3 headers');
  assert(
    deepEqual(result.headers, ['name', 'age', 'city']),
    'Headers should match'
  );
  assert(result.rows.length === 2, 'Should have 2 rows');
  assert(result.errors.length === 0, 'Should have no errors');
  assert(result.rows[0].name === 'John', 'First row name should be John');
  assert(result.rows[0].age === 30, 'First row age should be 30 (coerced to number)');
  assert(result.rows[1].city === 'San Francisco', 'City should be preserved');

  console.log('✓ Test 1: Basic CSV Parsing - PASSED');
}

/**
 * Test 2: Quoted Fields with Commas
 */
function testQuotedFields(): void {
  const csv = `name,address,comment
"Smith, John",123 Main St,"Lives in the city"
"Doe, Jane","456 Oak Ave, Apt 2","Has a dog"`;

